public int countClumps(int[] nums) {
    int count = 0;
    for (int i = 0; i < nums.length - 1; i++) {
        if (nums[i] == nums[i + 1]) {
            int j = i;
            while (j < nums.length - 1 && nums[j] == nums[j + 1]) {
                j++;
            }
            count++;
            i = j;
        }
    }
    return count;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0, right = 0;

    while (right < n) {
        if (nums[right] == 5) {
            while (left < right && nums[left] != 4) {
                left++;
            }

            if (left == right) {
